SELECT DATE_FORMAT(a.alarm_beginTime, '%Y-%m-%d %H:00:00') AS onDate, SUM(CASE WHEN a.alarm_rank = 0 THEN 1 ELSE 0 END) AS rank0, SUM(CASE WHEN a.alarm_rank = 1 THEN 1 ELSE 0 END) AS rank1, SUM(CASE WHEN a.alarm_rank = 2 THEN 1 ELSE 0 END) AS rank2, COUNT(*) AS count FROM alarm a
JOIN device d ON a.device_sn = d.device_sn
WHERE '2' = '2'
AND a.device_sn = #{deviceSn}
AND d.tenant_id = #{tenantId}
AND a.alarm_beginTime BETWEEN #{startTime} AND #{stopTime} AND a.alarm_type = '0' GROUP BY onDate ORDER BY onDate

SELECT DATE_FORMAT(a.alarm_beginTime, '%Y-%m-%d') AS onDate, SUM(CASE WHEN a.alarm_rank = 0 THEN 1 ELSE 0 END) AS rank0, SUM(IF(a.alarm_rank = 1, 1, 0)) AS rank1, SUM(CASE WHEN a.alarm_rank = 2 THEN 1 ELSE 0 END) AS rank2, COUNT(*) AS count FROM alarm a
JOIN device d ON a.device_sn = d.device_sn
WHERE '2' = '2'
AND a.device_sn = #{deviceSn}
AND d.tenant_id = #{tenantId}
AND a.alarm_beginTime BETWEEN #{startTime} AND #{stopTime} AND a.alarm_type = '0' GROUP BY onDate ORDER BY onDate

